import pymysql
import functions_framework
from urllib.parse import unquote

@functions_framework.http
def search_api(request):
    # Database connection configuration
    db_config = {
        'host': 'your-cloud-sql-host',
        'user': 'your-username',
        'password': 'your-password',
        'database': 'your-database',
        'charset': 'utf8mb4'
    }
    
    # Initialize connection
    connection = None
    try:
        connection = pymysql.connect(**db_config)
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        
        # Build dynamic query based on request parameters
        base_query = "SELECT * FROM your_table WHERE 1=1"
        params = []
        
        # Process each parameter
        for key, value in request.args.items():
            if key != 'table' and key != 'limit':
                # URL decode the value
                decoded_value = unquote(value)
                
                # Handle different operators
                if key.endswith('_gt'):
                    field = key[:-3]
                    base_query += f" AND `{field}` > %s"
                    params.append(decoded_value)
                elif key.endswith('_lt'):
                    field = key[:-3]
                    base_query += f" AND `{field}` < %s"
                    params.append(decoded_value)
                elif key.endswith('_like'):
                    field = key[:-5]
                    base_query += f" AND `{field}` LIKE %s"
                    params.append(f"%{decoded_value}%")
                elif key.endswith('_in'):
                    field = key[:-3]
                    values = decoded_value.split(',')
                    placeholders = ','.join(['%s'] * len(values))
                    base_query += f" AND `{field}` IN ({placeholders})"
                    params.extend(values)
                else:
                    # Exact match
                    base_query += f" AND `{key}` = %s"
                    params.append(decoded_value)
        
        # Add limit if specified
        limit = request.args.get('limit', 100)
        base_query += " LIMIT %s"
        params.append(int(limit))
        
        # Execute query
        cursor.execute(base_query, params)
        results = cursor.fetchall()
        
        return {
            'status': 'success',
            'data': results,
            'count': len(results)
        }
        
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }
    finally:
        if connection:
            connection.close()